import{_ as r,o,c as a,ag as n}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"简介","description":"","frontmatter":{},"headers":[],"relativePath":"docs/about/introduction.md","filePath":"docs/about/introduction.md","lastUpdated":null}'),e={name:"docs/about/introduction.md"};function s(i,t,l,g,d,c){return o(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h1><ul><li><p><strong>Maisi</strong> 为您提供全面的 AI 模型接口代理服务，以支持您的软件和应用程序，助您轻松应用领先的 AI 技术。</p></li><li><p>提供反向代理的 API 接口，无需境外网络环境即可便捷访问 <strong>OpenAI</strong>、<strong>Claude</strong>、<strong>Midjourney</strong>等 AI 模型，在自然语言处理、图像识别、智能推荐和自动问答等不同场景中发挥作用。</p></li><li><p>高度自由的 API 管理，可根据您需求轻松创建 API key 并管理使用金额,仅需修改接口地址为<code>https://api.maisi-ai.com</code>(国外)/<code>https://hk.maisi-ai.com</code>(国内)即可快速使用。</p></li><li><p>多种渠道来源*，官方/Azure/逆向等渠道，不同渠道享受不同折扣，可随时在令牌页面切换，详情请查看<a href="https://maisi-ai.com/prices/" target="_blank" rel="noreferrer">价格页面</a>。</p></li><li><p>国内用户使用本服务则代表您已阅读并同意遵守 <a href="https://www.cac.gov.cn/2023-07/13/c_1690898327029107.htm" target="_blank" rel="noreferrer">《生成式人工智能服务管理暂行办法》</a> 等相关法律法规。</p></li></ul><h2 id="服务优势" tabindex="-1">服务优势 <a class="header-anchor" href="#服务优势" aria-label="Permalink to &quot;服务优势&quot;">​</a></h2><ul><li><strong>全面兼容</strong>：支持所有调用 AI 的软件和应用。无论您是在开发聊天机器人、自然语言处理模型还是其他 AI 功能，我们都能为您提供全面的支持。</li><li><strong>功能强大</strong>：支持流式输出和连续对话等高级功能。您可以实现更加智能和自然的交互体验，让您的用户获得更加精准和有趣的回复。</li><li><strong>稳定高效</strong>：我们的系统经过精心优化，确保稳定有效的使用体验。无论您在国内还是国外，我们都提供快速可靠的服务，让您无需担忧网络延迟或不稳定的问题。</li><li><strong>安全可靠</strong>：重视用户隐私和数据安全，只负责数据转发，不保存数据信息，采取严格的安全措施来保护您的信息和交互数据。您可以放心使用我们的服务，专注于开发和创新。</li><li><strong>简单易用</strong>：提供简洁明了的界面和易于操作的流程，让您快速上手并集成 AI 的功能。无论您是开发者还是非技术人员，都能轻松使用我们的服务。</li><li><strong>模型全面</strong>：支持 OpenAI、Claude、Midjourney 等模型，其它大模型正在适配中。</li></ul><h2 id="关于渠道来源" tabindex="-1">关于渠道来源 <a class="header-anchor" href="#关于渠道来源" aria-label="Permalink to &quot;关于渠道来源&quot;">​</a></h2><p>模型供应商一般分 4 种类型的渠道：<strong>官方</strong>、<strong>合作商家</strong>、<strong>逆向</strong>、<strong>默认</strong>。 不同的供应商渠道价格也不同，官方 &gt; 合作商家 &gt; 逆向，逆向渠道的价格最低，但是稳定性和功能性也最差。</p><p>市面上很多中转站为了成本考虑，会混用供应商渠道，导致接口不稳定，价格不透明，甚至有安全隐患。</p><p>我们明码标价，您可以随时切换您想要使用的渠道，享受不同的折扣。</p><h3 id="官方" tabindex="-1"><strong>官方</strong> <a class="header-anchor" href="#官方" aria-label="Permalink to &quot;**官方**&quot;">​</a></h3><p>顾名思义，就是模型供应商自己提供的服务。</p><h3 id="合作商家" tabindex="-1"><strong>合作商家</strong> <a class="header-anchor" href="#合作商家" aria-label="Permalink to &quot;**合作商家**&quot;">​</a></h3><p>每家模型供应商除了自己<strong>官方</strong>提供的服务外，还和其他厂商合作，例如：<strong>OpenAI</strong>，他和<strong>Azure</strong>合作，<strong>Claude</strong>和<strong>亚马逊</strong>以及<strong>谷歌</strong>合作。 但是这些合作商家在 API 功能和新模型上会有滞后性。</p><h3 id="逆向" tabindex="-1"><strong>逆向</strong> <a class="header-anchor" href="#逆向" aria-label="Permalink to &quot;**逆向**&quot;">​</a></h3><p>逆向渠道是指通过技术方法方式将模型官方客服端服务转换为 API 接口形式提供调用，这种 API 接口只能用于<strong>聊天</strong>使用，无法使用函数调用等功能，并且稳定性差。</p>',14)])])}const u=r(e,[["render",s]]);export{h as __pageData,u as default};
